        [HttpGet("{invoiceId:int}")]
        public IActionResult GetInvoiceById(int invoiceId)
        {
            if (invoiceId <= 0)
            {
                return BadRequest(new { Error = "Invoice ID must be a positive integer." });
            }

            var currentUser = User.Identity?.Name;

            if (string.IsNullOrEmpty(currentUser) || !User.Identity.IsAuthenticated)
            {
                return Unauthorized(new { Error = "User is not authenticated." });
            }

            var invoice = _invoices.FirstOrDefault(i => i.InvoiceId == invoiceId);

            if (invoice == null)
            {
                return NotFound(new { Error = $"Invoice with ID {invoiceId} was not found." });
            }

            var response = new
            {
                invoice.InvoiceId,
                invoice.InvoiceNumber,
                invoice.CustomerName,
                invoice.CustomerEmail,
                invoice.InvoiceDate,
                invoice.DueDate,
                invoice.Status,
                Items = invoice.Items.Select(item => new
                {
                    item.ItemId,
                    item.Description,
                    item.Quantity,
                    item.UnitPrice,
                    item.Total
                }),
                invoice.Subtotal,
                invoice.TaxRate,
                invoice.TaxAmount,
                invoice.TotalAmount
            };

            return Ok(response);
        }
